children.css:
.question-taxonomy-page .taxonomy-shell { height: calc(100vh - 118px); min-height: 0; padding: 10px 14px 14px; box-sizing: border-box; overflow: hidden; }
.question-taxonomy-page .taxonomy-panel { height: 100%; min-height: 0; overflow: hidden; background: #fff; border: 1px solid #d8dee8; border-radius: 8px; }
.question-taxonomy-page .taxonomy-panel .layout-content, .question-taxonomy-page .taxonomy-panel .layout-content-inner { min-height: 0; overflow: hidden !important; }
.question-taxonomy-page .taxonomy-panel .layout-content-inner > div { min-height: 0; overflow: hidden !important; }
.question-taxonomy-page .taxonomy-tabs, .question-taxonomy-page .taxonomy-tab-page { height: 100%; min-height: 0; }
.question-taxonomy-page .taxonomy-toolbar-form.co-ui-form { padding: 0 !important; }
.question-taxonomy-page .taxonomy-toolbar-form .co-ui-form-item.ant-form-item { margin: 0 8px 8px 0 !important; }
.question-taxonomy-page .taxonomy-knowledge-tree .layout-content-inner > div { height: 100%; min-height: 0; display: flex; flex-direction: column; overflow: hidden !important; }
.question-taxonomy-page .taxonomy-tree-summary { flex: 0 0 auto; padding: 8px 12px; color: #4b5563; font-size: 12px; border-bottom: 1px solid #eef2f7; background: #fafcff; }
.question-taxonomy-page .taxonomy-tree-wrap { flex: 1 1 auto; min-height: 0; overflow: auto; padding: 8px 10px 10px; }
.question-taxonomy-page .taxonomy-tree-wrap .co-ui-tree { font-size: 13px; }
.question-taxonomy-page .taxonomy-dialog-form .co-ui-form-item.ant-form-item { margin-bottom: 12px; }
.question-taxonomy-page .taxonomy-status-enabled { color: #0f7b3a; font-weight: 700; }
.question-taxonomy-page .taxonomy-status-disabled { color: #8a2d2d; font-weight: 700; }
.question-taxonomy-page .co-ui-button.ant-btn { border-radius: 6px; }
.question-taxonomy-page .ant-table-wrapper, .question-taxonomy-page .ag-root-wrapper { min-height: 0; }
.question-taxonomy-page .taxonomy-knowledge-split { height: 100%; min-height: 0; overflow: hidden; }
.question-taxonomy-page .taxonomy-knowledge-split .taxonomy-subpanel { height: 100%; min-height: 0; overflow: hidden; background: #fff; }
.question-taxonomy-page .taxonomy-action-cell { display: flex; align-items: center; justify-content: center; }
.question-taxonomy-page .taxonomy-action-button { min-width: 52px; }
.question-taxonomy-page .pdf-knowledge-import-form .co-ui-form-item.ant-form-item { margin-bottom: 10px; }
.question-taxonomy-page .pdf-knowledge-import-summary { display: grid; grid-template-columns: repeat(auto-fit, minmax(138px, 1fr)); gap: 8px; }
.question-taxonomy-page .pdf-knowledge-import-metric { border: 1px solid #d8dee8; border-radius: 6px; padding: 8px 10px; background: #fff; min-width: 0; }
.question-taxonomy-page .pdf-knowledge-import-metric-label { color: #667085; font-size: 12px; line-height: 1.4; }
.question-taxonomy-page .pdf-knowledge-import-metric-value { color: #182230; font-size: 18px; font-weight: 700; line-height: 1.3; }
.question-taxonomy-page .pdf-knowledge-import-compare { display: grid; grid-template-columns: minmax(0, 1fr) minmax(0, 1fr); gap: 10px; min-height: 0; }
.question-taxonomy-page .pdf-knowledge-import-pane { min-height: 0; border: 1px solid #d8dee8; border-radius: 6px; background: #fff; overflow: hidden; }
.question-taxonomy-page .pdf-knowledge-import-pane-title { padding: 7px 10px; border-bottom: 1px solid #eef2f7; background: #fafcff; font-size: 13px; font-weight: 700; color: #344054; }
